request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName ?initPartRef ?loopType WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_3772a4c8_337f_4a64_a2fc_de2aebea6f5b> .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:initiatingParticipantRef ?initPartRef . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
}
ORDER BY ?taskName
LIMIT 30
